import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Calculate the required buffer size based on user input length
        byte[] buffer = new byte[userInput.length()];

        // Copy user input to buffer
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, Math.min(userInput.length(), buffer.length));

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
